import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import type { Consultation } from "@shared/schema";
import { apiRequest } from "@/lib/queryClient";

export default function Admin() {
  const queryClient = useQueryClient();

  const { data: consultations, isLoading } = useQuery<Consultation[]>({
    queryKey: ["/api/consultations"],
    queryFn: async () => {
      const response = await fetch("/api/consultations");
      return response.json();
    },
  });

  const updateContactedMutation = useMutation({
    mutationFn: async ({ id, contacted }: { id: number; contacted: boolean }) => {
      const response = await apiRequest(`/api/consultations/${id}/contacted`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ contacted }),
      });
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/consultations"] });
    },
  });

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-xl">Loading consultations...</div>
      </div>
    );
  }

  const totalConsultations = consultations?.length || 0;
  const contactedCount = consultations?.filter(c => c.contacted).length || 0;
  const pendingCount = totalConsultations - contactedCount;
  const todayCount = consultations?.filter(c => 
    new Date(c.createdAt).toDateString() === new Date().toDateString()
  ).length || 0;

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="container mx-auto px-4">
        <div className="mb-8">
          <h1 className="font-display text-4xl mb-4">Tableau de Bord Admin</h1>
          <p className="text-gray-600">Gérer les demandes de consultation et les suivis</p>
        </div>

        {/* Statistiques */}
        <div className="grid md:grid-cols-4 gap-4 mb-8">
          <Card>
            <CardContent className="p-4">
              <div className="text-2xl font-bold text-primary">{totalConsultations}</div>
              <div className="text-sm text-gray-600">Total Consultations</div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="p-4">
              <div className="text-2xl font-bold text-green-600">{contactedCount}</div>
              <div className="text-sm text-gray-600">Contactés</div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="p-4">
              <div className="text-2xl font-bold text-orange-600">{pendingCount}</div>
              <div className="text-sm text-gray-600">En attente</div>
            </CardContent>
          </Card>
          <Card>
            <CardContent className="p-4">
              <div className="text-2xl font-bold text-blue-600">{todayCount}</div>
              <div className="text-sm text-gray-600">Aujourd'hui</div>
            </CardContent>
          </Card>
        </div>

        <div className="grid gap-6">
          {consultations?.map((consultation) => (
            <Card key={consultation.id} className="bg-white">
              <CardHeader>
                <div className="flex justify-between items-start">
                  <div>
                    <CardTitle className="text-xl">{consultation.name}</CardTitle>
                    <p className="text-gray-600">{consultation.company}</p>
                  </div>
                  <div className="flex items-center gap-2">
                    <Badge variant={consultation.contacted ? "default" : "secondary"}>
                      {consultation.contacted ? "Contacté" : "En attente"}
                    </Badge>
                    <Badge variant="outline" className="ml-2">
                      Score: {consultation.leadScore}
                    </Badge>
                    <Button
                      size="sm"
                      variant={consultation.contacted ? "outline" : "default"}
                      onClick={() => 
                        updateContactedMutation.mutate({
                          id: consultation.id,
                          contacted: !consultation.contacted
                        })
                      }
                      disabled={updateContactedMutation.isPending}
                    >
                      {consultation.contacted ? "Marquer en attente" : "Marquer contacté"}
                    </Button>
                  </div>
                </div>
              </CardHeader>
              <CardContent>
                <div className="grid md:grid-cols-3 gap-4">
                  <div>
                    <h4 className="font-semibold mb-2">Informations Contact</h4>
                    <p><strong>Email:</strong> 
                      <a href={`mailto:${consultation.email}`} className="text-blue-600 hover:underline ml-1">
                        {consultation.email}
                      </a>
                    </p>
                    {consultation.phone && (
                      <p><strong>Téléphone:</strong> 
                        <a href={`tel:${consultation.phone}`} className="text-blue-600 hover:underline ml-1">
                          {consultation.phone}
                        </a>
                      </p>
                    )}
                    <p><strong>Taille Entreprise:</strong> {consultation.companySize || 'Non fournie'}</p>
                  </div>
                  <div>
                    <h4 className="font-semibold mb-2">Détails Business</h4>
                    <p><strong>Revenus:</strong> {consultation.revenue || 'Non fournis'}</p>
                    <p><strong>Industrie:</strong> {consultation.industry || 'Non fournie'}</p>
                    <p><strong>Budget:</strong> {consultation.budget || 'Non fourni'}</p>
                    <p><strong>Timeline:</strong> {consultation.timeline || 'Non fournie'}</p>
                  </div>
                  <div>
                    <h4 className="font-semibold mb-2">Qualification Lead</h4>
                    {consultation.leadScore && (
                      <div className="mb-2">
                        <Badge variant={
                          consultation.leadScore.startsWith('A') ? 'default' :
                          consultation.leadScore.startsWith('B') ? 'secondary' :
                          'outline'
                        } className="text-sm">
                          Score: {consultation.leadScore}
                        </Badge>
                      </div>
                    )}
                    <p className="text-sm"><strong>Soumis:</strong> {new Date(consultation.createdAt).toLocaleDateString('fr-FR')}</p>
                    <p className="text-sm"><strong>Heure:</strong> {new Date(consultation.createdAt).toLocaleTimeString('fr-FR')}</p>
                  </div>
                </div>

                {(consultation.automationGoals || consultation.currentChallenges) && (
                  <div className="mt-4">
                    <h4 className="font-semibold mb-2">Objectifs & Défis</h4>
                    {consultation.currentChallenges && (
                      <p className="text-gray-700 mb-2 p-2 bg-red-50 rounded">
                        <strong>Défis Actuels:</strong> {consultation.currentChallenges}
                      </p>
                    )}
                    {consultation.automationGoals && (
                      <p className="text-gray-700 p-2 bg-green-50 rounded">
                        <strong>Objectifs d'Automatisation:</strong> {consultation.automationGoals}
                      </p>
                    )}
                  </div>
                )}

                <div className="mt-4 pt-4 border-t flex justify-between items-center">
                  <div className="flex gap-2">
                    <Button size="sm" variant="outline" asChild>
                      <a href={`mailto:${consultation.email}?subject=Consultation Minecore Group&body=Bonjour ${consultation.name},%0D%0A%0D%0AMerci pour votre intérêt pour nos services d'automatisation...`}>
                        ✉️ Envoyer Email
                      </a>
                    </Button>
                    {consultation.phone && (
                      <Button size="sm" variant="outline" asChild>
                        <a href={`tel:${consultation.phone}`}>
                          📞 Appeler
                        </a>
                      </Button>
                    )}
                  </div>
                  <p className="text-sm text-gray-500">
                    ID: {consultation.id} • {new Date(consultation.createdAt).toLocaleDateString('fr-FR')}
                  </p>
                </div>
              </CardContent>
            </Card>
          ))}

          {(!consultations || consultations.length === 0) && (
            <Card>
              <CardContent className="text-center py-8">
                <p className="text-gray-600">No consultation requests yet.</p>
              </CardContent>
            </Card>
          )}
        </div>
      </div>
    </div>
  );
}

