        author: "Financial Analyst",
        readTime: "10 min read",
        category: "Finance",
        featured: true,
      }
    ];


  }

  // Consultation methods
  async createConsultation(insertConsultation: InsertConsultation): Promise<Consultation> {
    const id = this.currentConsultationId++;
    const consultation: Consultation = {
      ...insertConsultation,
      id,
      createdAt: new Date(),
      contacted: false,
      phone: insertConsultation.phone ?? null,
      additionalInfo: insertConsultation.additionalInfo ?? null,
      leadScore: insertConsultation.leadScore ?? null,
    };
    this.consultations.set(id, consultation);
    return consultation;
  }

  async getConsultations(): Promise<Consultation[]> {
    return Array.from(this.consultations.values()).sort(
      (a, b) => b.createdAt.getTime() - a.createdAt.getTime()
    );
  }

  async getConsultation(id: number): Promise<Consultation | undefined> {
    return this.consultations.get(id);
  }

  async updateConsultationContacted(id: number, contacted: boolean): Promise<Consultation | undefined> {
    const consultation = this.consultations.get(id);
    if (consultation) {
      consultation.contacted = contacted;
      return consultation;
    }
    return undefined;
  }

  // Blog methods
  async createBlogPost(insertPost: InsertBlogPost): Promise<BlogPost> {
    const id = this.currentBlogPostId++;
    const post: BlogPost = {
      ...insertPost,
      id,
      createdAt: new Date(),
      updatedAt: new Date(),
      published: insertPost.published ?? false,
      author: insertPost.author ?? "Anonymous",
      readTime: insertPost.readTime ?? "5 min read",
      category: insertPost.category ?? "General",
      featured: insertPost.featured ?? false,
    };
    this.blogPosts.set(id, post);
    return post;
  }

  async getBlogPosts(published?: boolean): Promise<BlogPost[]> {
    let posts = Array.from(this.blogPosts.values());

    if (published !== undefined) {
      posts = posts.filter(post => post.published === published);
    }

    return posts.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());
  }

  async getBlogPost(slug: string): Promise<BlogPost | undefined> {
    return Array.from(this.blogPosts.values()).find(post => post.slug === slug);
  }

  async updateBlogPost(id: number, updates: Partial<InsertBlogPost>): Promise<BlogPost | undefined> {
    const post = this.blogPosts.get(id);
    if (post) {
      Object.assign(post, updates, { updatedAt: new Date() });
      return post;
