import { useState } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { insertConsultationSchema, type InsertConsultation } from "@shared/schema";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Progress } from "@/components/ui/progress";
import { useToast } from "@/hooks/use-toast";
import { useLanguage } from "@/hooks/use-language";
import { apiRequest } from "@/lib/queryClient";
import { calculateLeadScore } from "@/lib/lead-scoring";

export function MultiStepConsultationForm() {
  const { toast } = useToast();
  const { t } = useLanguage();
  const queryClient = useQueryClient();
  const [currentStep, setCurrentStep] = useState(1);
  const [isSubmitted, setIsSubmitted] = useState(false);

  const form = useForm<InsertConsultation>({
    resolver: zodResolver(insertConsultationSchema),
    defaultValues: {
      name: "",
      email: "",
      phone: "",
      company: "",
      jobTitle: "",
      companySize: "",
      industry: "",
      revenue: "",
      growth: "",
      currentTools: "",
      teamSize: "",
      biggestChallenge: "",
      timeSpentManualTasks: "",
      automationGoals: "",
      budget: "",
      timeline: "",
      decisionMaker: "",
      previousAutomation: "",
      urgency: "",
      additionalInfo: "",
    },
  });

  const mutation = useMutation({
    mutationFn: async (data: InsertConsultation) => {
      const response = await apiRequest("POST", "/api/consultations", data);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/consultations"] });
      setIsSubmitted(true);

      // Google Ads conversion tracking
      if (typeof gtag !== 'undefined') {
        gtag('event', 'conversion', {
          'send_to': 'AW-17032394525',
          'value': 1,
          'currency': 'USD'
        });
        gtag('event', 'submit_lead_form', {
          'currency': 'USD',
          'value': 1
        });
      }

      toast({
        title: "Application Submitted!",
        description: "We'll review your application and contact you within 24 hours.",
      });
    },
    onError: (error) => {
      console.error("Consultation submission error:", error);
      toast({
        title: "Error",
        description: "Failed to submit application. Please try again.",
        variant: "destructive",
      });
    },
  });

  const validateStep = async () => {
    const fields = getStepFields(currentStep);
    const result = await form.trigger(fields);
    return result;
  };

  const getStepFields = (step: number): (keyof InsertConsultation)[] => {
    switch (step) {
      case 1:
        return ["name", "email", "company", "jobTitle", "companySize", "industry"];
      case 2:
        return ["revenue", "growth", "currentTools", "teamSize", "biggestChallenge", "timeSpentManualTasks"];
      case 3:
        return ["automationGoals", "budget", "timeline", "decisionMaker", "previousAutomation", "urgency"];
      default:
        return [];
    }
  };

  const handleNext = async () => {
    const isValid = await validateStep();
    if (isValid && currentStep < 3) {
      setCurrentStep(currentStep + 1);
    } else if (!isValid) {
      // Show validation errors
      const fields = getStepFields(currentStep);
      fields.forEach(field => {
        form.trigger(field);
      });
    }
  };

  const handlePrevious = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const onSubmit = (data: InsertConsultation) => {
    // Prevent submission if not on step 3
    if (currentStep !== 3) {
      console.log('Form submission blocked: must complete all 3 steps');
      return false;
    }

    // Validate all required step 3 fields
    const step3Fields = ['automationGoals', 'budget', 'timeline', 'decisionMaker', 'previousAutomation', 'urgency'];
    const missingFields = step3Fields.filter(field => !data[field as keyof InsertConsultation]);

    if (missingFields.length > 0) {
      console.log('Missing required fields:', missingFields);
      return false;
    }

    const leadScore = calculateLeadScore(data);
    const dataWithScore = { ...data, leadScore };
    mutation.mutate(dataWithScore);
  };

  if (isSubmitted) {
    return (
      <div className="text-center py-12">
        <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6">
          <i className="fas fa-check text-green-600 text-3xl"></i>
        </div>
        <h3 className="font-display text-2xl mb-4 text-black">Application Submitted!</h3>
        <p className="text-gray-600 mb-6 max-w-md mx-auto">
          Thank you for your detailed application. Our team will review your information and contact you within 24 hours to schedule your consultation.
        </p>
        <div className="bg-gray-50 rounded-lg p-4 max-w-md mx-auto">
          <h4 className="font-semibold mb-2">What happens next?</h4>
          <ul className="text-sm text-gray-600 space-y-1">
            <li>• Qualification review (2-4 hours)</li>
            <li>• Consultation scheduling (24 hours)</li>
            <li>• Custom automation strategy (consultation call)</li>
          </ul>
        </div>
      </div>
    );
  }

  const progress = (currentStep / 3) * 100;

  return (
    <div className="max-w-2xl mx-auto">
      {/* Progress Bar */}
      <div className="mb-8">
        <div className="flex justify-between text-sm text-gray-600 mb-2">
          <span>Step {currentStep} of 3</span>
          <span>{Math.round(progress)}% Complete</span>
        </div>
        <Progress value={progress} className="h-2" />
      </div>

      {/* Step Headers */}
      <div className="text-center mb-8">
        {currentStep === 1 && (
          <div>
            <h3 className="font-display text-2xl mb-2 text-black">{t('companyInformation')}</h3>
            <p className="text-gray-600">{t('tellUsAboutBusiness')}</p>
          </div>
        )}
        {currentStep === 2 && (
          <div>
            <h3 className="font-display text-2xl mb-2 text-black">Current Operations</h3>
            <p className="text-gray-600">Help us understand your current processes and challenges</p>
          </div>
        )}
        {currentStep === 3 && (
          <div>
            <h3 className="font-display text-2xl mb-2 text-black">Automation Goals</h3>
            <p className="text-gray-600">Define your automation objectives and requirements</p>
          </div>
        )}
      </div>

      <Form {...form}>
        <form 
          onSubmit={(e) => {
            // Block form submission if not on step 3
            if (currentStep !== 3) {
              e.preventDefault();
              console.log('Form submission prevented: not on final step');
              return false;
            }
            form.handleSubmit(onSubmit)(e);
          }} 
          className="space-y-6" 
          onKeyDown={(e) => {
            // Prevent form submission on Enter key unless on step 3
            if (e.key === 'Enter' && currentStep !== 3) {
              e.preventDefault();
            }
          }}
        >
          {/* Step 1: Company Information */}
          {currentStep === 1 && (
            <div className="space-y-4">
              <div className="grid md:grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="name"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-black">{t('fullName')} *</FormLabel>
                      <FormControl>
                        <Input placeholder={t('yourFullName')} {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="email"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-black">{t('businessEmail')} *</FormLabel>
                      <FormControl>
                        <Input type="email" placeholder="you@company.com" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              <div className="grid md:grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="phone"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-black">{t('phoneNumber')}</FormLabel>
                      <FormControl>
                        <Input type="tel" placeholder="+1 (555) 123-4567" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="company"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-black">{t('companyName')} *</FormLabel>
                      <FormControl>
                        <Input placeholder={t('yourCompany')} {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              <FormField
                control={form.control}
                name="jobTitle"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-black">{t('jobTitle')} *</FormLabel>
                    <FormControl>
                      <Input placeholder={t('jobTitlePlaceholder')} {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <div className="grid md:grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="companySize"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-black">{t('companySize')} *</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder={t('selectCompanySize')} />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="solo">Solo entrepreneur</SelectItem>
                          <SelectItem value="2-5">2-5 employees</SelectItem>
                          <SelectItem value="6-20">6-20 employees</SelectItem>
                          <SelectItem value="21-50">21-50 employees</SelectItem>
                          <SelectItem value="51-200">51-200 employees</SelectItem>
                          <SelectItem value="200+">200+ employees</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="industry"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-black">{t('industry')} *</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder={t('selectIndustry')} />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="ecommerce">E-commerce</SelectItem>
                          <SelectItem value="saas">SaaS/Software</SelectItem>
                          <SelectItem value="professional-services">Professional Services</SelectItem>
                          <SelectItem value="healthcare">Healthcare</SelectItem>
                          <SelectItem value="finance">Finance</SelectItem>
                          <SelectItem value="real-estate">Real Estate</SelectItem>
                          <SelectItem value="manufacturing">Manufacturing</SelectItem>
                          <SelectItem value="retail">Retail</SelectItem>
                          <SelectItem value="education">Education</SelectItem>
                          <SelectItem value="other">Other</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>
            </div>
          )}

          {/* Step 2: Current Operations */}
          {currentStep === 2 && (
            <div className="space-y-4">
              <div className="grid md:grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="revenue"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-black">Annual Revenue *</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder="Select revenue range" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="under-100k">Under $100K</SelectItem>
                          <SelectItem value="100k-500k">$100K - $500K</SelectItem>
                          <SelectItem value="500k-1m">$500K - $1M</SelectItem>
                          <SelectItem value="1m-5m">$1M - $5M</SelectItem>
                          <SelectItem value="5m-10m">$5M - $10M</SelectItem>
                          <SelectItem value="10m+">$10M+</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="growth"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-black">Year-over-Year Growth *</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder="Select growth rate" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="declining">Declining</SelectItem>
                          <SelectItem value="0-10">0-10%</SelectItem>
                          <SelectItem value="10-25">10-25%</SelectItem>
                          <SelectItem value="25-50">25-50%</SelectItem>
                          <SelectItem value="50-100">50-100%</SelectItem>
                          <SelectItem value="100+">100%+</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              <FormField
                control={form.control}
                name="currentTools"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-black">Current Tools & Systems *</FormLabel>
                    <Select onValueChange={field.onChange} defaultValue={field.value}>
                      <FormControl>
                        <SelectTrigger>
                          <SelectValue placeholder="Select your current tools" />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent>
                        <SelectItem value="basic-spreadsheets">Basic (Spreadsheets, Email)</SelectItem>
                        <SelectItem value="crm-basic">CRM + Basic Tools</SelectItem>
                        <SelectItem value="project-management">Project Management Suite</SelectItem>
                        <SelectItem value="integrated-suite">Integrated Business Suite</SelectItem>
                        <SelectItem value="custom-solutions">Custom Solutions</SelectItem>
                        <SelectItem value="minimal-tools">Minimal/Manual Process</SelectItem>
                      </SelectContent>
                    </Select>
                    <FormMessage />
