                      <FormLabel className="text-black">Time on Manual Tasks *</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder="Hours per week" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="0-5">0-5 hours/week</SelectItem>
                          <SelectItem value="5-15">5-15 hours/week</SelectItem>
                          <SelectItem value="15-30">15-30 hours/week</SelectItem>
                          <SelectItem value="30-40">30-40 hours/week</SelectItem>
                          <SelectItem value="40+">40+ hours/week</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              <FormField
                control={form.control}
                name="biggestChallenge"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-black">Biggest Operational Challenge *</FormLabel>
                    <Select onValueChange={field.onChange} defaultValue={field.value}>
                      <FormControl>
                        <SelectTrigger>
                          <SelectValue placeholder="Select your biggest challenge" />
