                        <SelectItem value="reporting-analytics">Reporting and analytics</SelectItem>
                        <SelectItem value="team-coordination">Team coordination</SelectItem>
                        <SelectItem value="customer-service">Customer service bottlenecks</SelectItem>
                        <SelectItem value="scaling-operations">Scaling operations efficiently</SelectItem>
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>
          )}

          {/* Step 3: Automation Goals */}
          {currentStep === 3 && (
            <div className="space-y-4">
              <FormField
                control={form.control}
                name="automationGoals"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-black">Primary Automation Goals *</FormLabel>
                    <Select onValueChange={field.onChange} defaultValue={field.value}>
                      <FormControl>
                        <SelectTrigger>
                          <SelectValue placeholder="Select your automation goals" />
