                      </FormControl>
                      <SelectContent>
                        <SelectItem value="reduce-manual-work">Reduce manual work by 50%+</SelectItem>
                        <SelectItem value="improve-customer-experience">Improve customer experience</SelectItem>
                        <SelectItem value="increase-sales-efficiency">Increase sales efficiency</SelectItem>
                        <SelectItem value="better-data-insights">Better data and insights</SelectItem>
                        <SelectItem value="scale-without-hiring">Scale without hiring more staff</SelectItem>
                        <SelectItem value="eliminate-errors">Eliminate human errors</SelectItem>
