              <div className="grid md:grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="decisionMaker"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-black">Decision Making Authority *</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder="Your role in decisions" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="final-decision">I make final decisions</SelectItem>
                          <SelectItem value="recommend">I recommend, others decide</SelectItem>
                          <SelectItem value="influence">I influence decisions</SelectItem>
                          <SelectItem value="research">I research for others</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="urgency"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-black">Priority Level *</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder="How urgent?" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="critical">Critical - Need solution now</SelectItem>
                          <SelectItem value="high">High - Within next quarter</SelectItem>
                          <SelectItem value="medium">Medium - Nice to have</SelectItem>
                          <SelectItem value="low">Low - Future consideration</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              <FormField
                control={form.control}
                name="previousAutomation"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-black">Previous Automation Experience *</FormLabel>
                    <Select onValueChange={field.onChange} defaultValue={field.value}>
                      <FormControl>
                        <SelectTrigger>
                          <SelectValue placeholder="Select your experience level" />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent>
                        <SelectItem value="complete-beginner">Complete beginner</SelectItem>
                        <SelectItem value="basic-tools">Used basic automation tools</SelectItem>
                        <SelectItem value="tried-failed">Tried before but failed</SelectItem>
                        <SelectItem value="partial-success">Some success, want to expand</SelectItem>
                        <SelectItem value="experienced">Experienced, looking to optimize</SelectItem>
                        <SelectItem value="diy-attempts">DIY attempts with mixed results</SelectItem>
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="additionalInfo"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-black">Additional Information</FormLabel>
                    <FormControl>
                      <Textarea 
                        placeholder="Anything else you'd like us to know?"
                        className="min-h-[80px]"
                        {...field} 
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>
          )}

          {/* Navigation Buttons */}
          <div className="flex justify-between pt-6">
            <Button
              type="button"
              variant="outline"
              onClick={handlePrevious}
              disabled={currentStep === 1}
              className="px-8"
            >
              {t('previous')}
            </Button>

            {currentStep < 3 ? (
              <Button
                type="button"
                onClick={handleNext}
                className="px-8 bg-black text-white hover:bg-gray-800"
              >
                {t('nextStep')}
              </Button>
            ) : (
              <Button
                type="submit"
                disabled={mutation.isPending || currentStep !== 3}
                className="px-8 bg-black text-white hover:bg-gray-800"
                onClick={(e) => {
                  if (currentStep !== 3) {
                    e.preventDefault();
                    console.log('Submit button clicked but not on step 3');
                    return false;
                  }
                }}
              >
                {mutation.isPending ? "Submitting..." : "Submit Application"}
              </Button>
            )}
          </div>
        </form>
      </Form>
    </div>
  );
}

